1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	type StepResult = { premium: number };
7	type ScenarioResult = { results: StepResult[] };
8	
9	const BASE_PRICES: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
19	
20	const CURSED_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	
24	const isCursed = (item: Item): boolean => item.cursed === true;
25	const isHighlyEnchanted = (item: Item): boolean =>
26	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
27	
28	const surchargeRate = (item: Item): number =>
29	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
30	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
31	
32	const itemPremium = (item: Item): number => {
33	  const base = basePriceOf(item);
34	  return base + base * surchargeRate(item);
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const BLOCK_SIZE = 3;
39	const BLOCK_PRICE = 60;
40	
41	const groupByType = (items: Item[]): Map<string, Item[]> => {
42	  const groups = new Map<string, Item[]>();
43	  for (const item of items) {
44	    const existing = groups.get(item.type) ?? [];
45	    existing.push(item);
46	    groups.set(item.type, existing);
47	  }
48	  return groups;
49	};
50	
51	const groupPremium = (type: string, members: Item[]): number => {
52	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
53	  return members.reduce((sum, item) => sum + itemPremium(item), 0);
54	};
55	
56	const itemsSubtotal = (items: Item[]): number =>
57	  Array.from(groupByType(items)).reduce(
58	    (total, [type, members]) => total + groupPremium(type, members),
59	    0,
60	  );
61	
62	const LOYALTY_DISCOUNT_RATE = 0.2;
63	const LOYALTY_YEARS_THRESHOLD = 2;
64	
65	const isLoyalCustomer = (customer: Scenario["customer"]): boolean =>
66	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
67	
68	const quotePremium = (items: Item[], customer: Scenario["customer"]): number => {
69	  const subtotal = itemsSubtotal(items);
70	  const discounted = isLoyalCustomer(customer)
71	    ? subtotal - subtotal * LOYALTY_DISCOUNT_RATE
72	    : subtotal;
73	  return discounted + PROCESSING_FEE;
74	};
75	
76	const runStep = (step: QuoteStep, customer: Scenario["customer"]): StepResult => ({
77	  premium: quotePremium(step.items, customer),
78	});
79	
80	export const runScenario = (input: Scenario): ScenarioResult => ({
81	  results: input.steps.map((step) => runStep(step, input.customer)),
82	});
