const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

const isLoyalCustomer = (customer: Scenario["customer"]): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscountRate = (customer: Scenario["customer"]): number =>
  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;

const quotePremium = (items: Item[], customer: Scenario["customer"]): number => {
  const subtotal = itemsSubtotal(items);
  return subtotal * (1 - loyaltyDiscountRate(customer)) + PROCESSING_FEE;
};
